#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        A = int(next(it)); B = int(next(it)); C = int(next(it)); D = int(next(it))
        price1 = A - C
        price2 = B - D
        if price1 < price2:
            out_lines.append("First")
        elif price2 < price1:
            out_lines.append("Second")
        else:
            out_lines.append("Any")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

